using namespace std;

struct Query {
    int l, r, threshold;
    int idx;
};

vector<long long> solve(vector<long long> nums, vector<vector<long long>> queries) {
    int n = nums.size();
    int q = queries.size();
    vector<long long> ans(q, -1);

    if (n == 0) {
        return ans;
    }

    int block_size = sqrt(n);
    if (block_size == 0) block_size = 1;

    vector<Query> qs;
    for (int i = 0; i < q; i++) {
        int l = (int)queries[i][0];
        int r = (int)queries[i][1];
        int threshold = (int)queries[i][2];
        qs.push_back({l, r, threshold, i});
    }

    sort(qs.begin(), qs.end(), [block_size](const Query &a, const Query &b) {
        int block_a = a.l / block_size;
        int block_b = b.l / block_size;
        if (block_a != block_b) {
            return block_a < block_b;
        }
        return (block_a & 1) ? (a.r > b.r) : (a.r < b.r);
    });

    unordered_map<long long, int> freqMap;
    unordered_map<int, set<long long>> freqToSet;
    multiset<int> allFreqs;

    int L = 0, R = -1;

    auto add = [&](long long x) {
        auto it = freqMap.find(x);
        int oldFreq = (it != freqMap.end()) ? it->second : 0;
        if (oldFreq) {
            auto iter = allFreqs.find(oldFreq);
            if (iter != allFreqs.end()) {
                allFreqs.erase(iter);
            }
            freqToSet[oldFreq].erase(x);
            if (freqToSet[oldFreq].empty()) {
                freqToSet.erase(oldFreq);
            }
        }
        int newFreq = oldFreq + 1;
        freqMap[x] = newFreq;
        allFreqs.insert(newFreq);
        freqToSet[newFreq].insert(x);
    };

    auto remove_val = [&](long long x) {
        int oldFreq = freqMap[x];
        auto iter = allFreqs.find(oldFreq);
        if (iter != allFreqs.end()) {
            allFreqs.erase(iter);
        }
        freqToSet[oldFreq].erase(x);
        if (freqToSet[oldFreq].empty()) {
            freqToSet.erase(oldFreq);
        }

        int newFreq = oldFreq - 1;
        if (newFreq > 0) {
            freqMap[x] = newFreq;
            allFreqs.insert(newFreq);
            freqToSet[newFreq].insert(x);
        } else {
            freqMap.erase(x);
        }
    };

    for (const Query &query : qs) {
        while (R < query.r) {
            R++;
            add(nums[R]);
        }
        while (R > query.r) {
            remove_val(nums[R]);
            R--;
        }
        while (L < query.l) {
            remove_val(nums[L]);
            L++;
        }
        while (L > query.l) {
            L--;
            add(nums[L]);
        }

        if (allFreqs.empty()) {
            ans[query.idx] = -1;
        } else {
            int currentMaxFreq = *allFreqs.rbegin();
            if (currentMaxFreq < query.threshold) {
                ans[query.idx] = -1;
            } else {
                ans[query.idx] = *(freqToSet[currentMaxFreq].begin());
            }
        }
    }

    return ans;
}
